import{_ as i,r as o,o as d,c as l,b as n,e as s,w as c,d as a,f as t}from"./app-55c326ac.js";const r={},p=n("h1",{id:"_05-操作docker容器",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#_05-操作docker容器","aria-hidden":"true"},"#"),a(" 05. 操作Docker容器")],-1),u={class:"table-of-contents"},b=t(`<p><strong>前言</strong> 容器是docker的核心概念<br> 简单的说，容器是独立运行的一个或一组应用，以及他们的运行态环境。对应的，虚拟机可以理解为模拟运行的一整套操作系统（提供了运行态环境和其他系统环境）和跑在上面的应用。<br> 主要掌握--如何管理一个容器，包括创建，启动，停止，删除等等。</p><h2 id="启动容器" tabindex="-1"><a class="header-anchor" href="#启动容器" aria-hidden="true">#</a> 启动容器</h2><h3 id="启动容器-1" tabindex="-1"><a class="header-anchor" href="#启动容器-1" aria-hidden="true">#</a> 启动容器</h3><p>启动容器的两种方式，一种是基于镜像新建一个容器并启动。另一种是将终止状态的容器重新启动。<br> 由于Docker的容器实在太轻量级了，很多时候用户都是随时删除和新创建容器</p><h3 id="新建并启动" tabindex="-1"><a class="header-anchor" href="#新建并启动" aria-hidden="true">#</a> 新建并启动</h3><p>所需要的命令 <code>docker run</code></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 从容器-输出一个“Hello world”-之后终止容器</span>
<span class="token function">docker</span> run centos:7 /bin/echo <span class="token string">&quot;Hello wang&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>下面来启动一个bash终端，允许用户进行交互</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token punctuation">[</span>root@Client_02 ~<span class="token punctuation">]</span><span class="token comment"># docker run -it centos:7 /bin/bash       #这是用来启动容器创建一个bash终端</span>
<span class="token punctuation">[</span>root@29bd2b63c1af /<span class="token punctuation">]</span><span class="token comment">#      #这里，就是我们启动容器创建的终端</span>
 <span class="token parameter variable">-t</span> 选项让Docker分配一个伪终端（pseudo-tty）并绑定到容器的标准输入上，
 <span class="token parameter variable">-i</span> 则让容器的标准输入保持打开

在交互模式下，用户可以通过创建的终端来输入命令。for example:
<span class="token punctuation">[</span>root@29bd2b63c1af /<span class="token punctuation">]</span><span class="token comment"># ls</span>
anaconda-post.log  dev  home  lib64  mnt  proc  run   srv  tmp  var
bin                etc  lib   media  opt  root  sbin  sys  usr
<span class="token punctuation">[</span>root@29bd2b63c1af /<span class="token punctuation">]</span><span class="token comment"># pwd</span>
/
<span class="token punctuation">[</span>root@29bd2b63c1af /<span class="token punctuation">]</span><span class="token comment"># touch /mnt/a.txt</span>
<span class="token punctuation">[</span>root@29bd2b63c1af /<span class="token punctuation">]</span><span class="token comment"># exit     #退出容器</span>
<span class="token function">docker</span> container <span class="token function">ls</span> <span class="token parameter variable">-a</span>       <span class="token comment">#列出所有容器</span>
<span class="token function">docker</span> <span class="token function">diff</span> 容器名或sha256值     <span class="token comment">#列出某个容器的历史操作</span>
<span class="token function">docker</span> stop 容器名或sha256值     <span class="token comment">#关闭容器</span>
<span class="token function">docker</span> hostory   镜像名:标签     <span class="token comment">#列出镜像的历史操作</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>当利用<code>docker run</code>来创建容器时，Docker在后台运行的标准操作包括：</p><ul><li>检查本地是否存在指定的镜像，不存在就从公有仓库下载</li><li>利用镜像创建并启动一个容器</li><li>分配一个文件系统，并在只读的镜像层外面挂载一层可读写层</li><li>从宿主主机配置的网桥接口中桥接一个虚拟接口到容器中</li><li>从地址池配置一个IP地址给容器</li><li>执行用户指定的应用程序</li><li>执行完毕后容器被终止</li></ul><h3 id="启动已终止的容器" tabindex="-1"><a class="header-anchor" href="#启动已终止的容器" aria-hidden="true">#</a> 启动已终止的容器</h3><p>可以利用<code>docker container start</code>命令，直接将一个已经终止的容器启动运行（貌似 <code>docker exec -it 容器名 bash</code> 也可以启动 ）<br> 容器的核心为所执行的应用程序，所需要的资源都是应用程序运行所必须的。除此之外，并没有其他的资源。可以再伪终端中利用ps或top来查看进程信息</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token punctuation">[</span>root@29bd2b63c1af /<span class="token punctuation">]</span><span class="token comment"># ps</span>
  PID TTY          TIME CMD
    <span class="token number">1</span> pts/0    00:00:00 <span class="token function">bash</span>
   <span class="token number">16</span> pts/0    00:00:00 <span class="token function">ps</span>
<span class="token punctuation">[</span>root@29bd2b63c1af /<span class="token punctuation">]</span><span class="token comment"># top</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>表明，容器中仅运行了指定的bash应用，这特点使Docker对资源的利用率极高。</p><hr><h2 id="后台运行" tabindex="-1"><a class="header-anchor" href="#后台运行" aria-hidden="true">#</a> 后台运行</h2><p>大部分时候，需要让Docker在后台运行而不是直接把执行命令的结果输出在当前宿主机下。此时，可以通过添加 <code>-d</code>参数实现。<br> 例子 不使用 <code>-d</code>参数运行容器</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> run centos:7 /bin/sh <span class="token parameter variable">-c</span> <span class="token string">&quot;while true; do echo hello world; sleep 1; done&quot;</span>
<span class="token comment">## 此时结果会输出到宿主机下面</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>使用<code>-d</code>参数运行容器</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> run <span class="token parameter variable">-d</span> centos:7 /bin/sh <span class="token parameter variable">-c</span> <span class="token string">&quot;while true;do echo hello world;sleep 1;done&quot;</span>
b1308ef7af422764e105e93e8520df8402258ed7afddf2a9a30c4bb3b5e386b9

<span class="token comment">## 此时结果不会输出到宿主机下面</span>
<span class="token comment"># 要查看输出结果 </span>
<span class="token function">docker</span> logs
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>需要注意：容器是否会长久运行，是和<code>docker run</code>指定的命令有关，和<code>-d</code>参数无关<br> 使用<code>id</code>参数启动后会返回一个唯一的ID，可以通过<code>docker container ls</code>命令来查看容器信息</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> container <span class="token function">ls</span> <span class="token parameter variable">-a</span>

<span class="token comment"># 要获取容器的输出信息，可以通过 docker container logs  命令</span>
<span class="token function">docker</span> container logs <span class="token punctuation">[</span>container ID or NAMES<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="终止容器" tabindex="-1"><a class="header-anchor" href="#终止容器" aria-hidden="true">#</a> 终止容器</h2><p>可以使用<code>docker container stop</code>来终止一个运行中的容器<br> 此外，当Docker容器中指定的应用终结时，容器也自动终止<br> 如上面启动了一个终端的容器，用户通过<code>exit</code>命令或<code>ctrl+d</code>来退出终端时，所创建的容器立刻终止。<br> 终止状态的容器可以用<code>docker container ls -a</code>来查看。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> container <span class="token function">ls</span> <span class="token parameter variable">-a</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>处于终止状态的容器，可以通过 <code>docker container start</code>命令重新启动<br> 还有 <code>docker container restart</code>命令会将一个运行状态的容器终止，然后在重新启动它。</p><hr><h2 id="进入容器" tabindex="-1"><a class="header-anchor" href="#进入容器" aria-hidden="true">#</a> 进入容器</h2><p>使用 <code>-d</code>参数时，容器启动后会进入后台运行<br> 当需要进入容器进行操作，可以使用<code>docker attach</code>或者<code>docker exec</code>，建议使用 <code>docker exec</code>命令。</p><h3 id="attach命令" tabindex="-1"><a class="header-anchor" href="#attach命令" aria-hidden="true">#</a> attach命令</h3><p>使用attach命令</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> run <span class="token parameter variable">-d</span> <span class="token parameter variable">-it</span> centos:7
<span class="token function">docker</span> container <span class="token function">ls</span>
<span class="token function">docker</span> attach 容器ID号
<span class="token comment">## 说明：如果从这个stdin中exit，会导致容器的停止</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="使用exec命令" tabindex="-1"><a class="header-anchor" href="#使用exec命令" aria-hidden="true">#</a> 使用exec命令</h3><h4 id="i-t参数" tabindex="-1"><a class="header-anchor" href="#i-t参数" aria-hidden="true">#</a> -i -t参数</h4><p><code>docker exec</code>后边可以跟多个参数，这里主要是-i -t参数<br> 只有<code>-i</code>参数时，由于没有分配伪终端，界面没有我们熟悉的Linux命令提示符。但命令执行结果仍然可以返回。<br><code>-i -t</code>参数一起使用，就是熟悉的linux命令提示符</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> run <span class="token parameter variable">-d</span> <span class="token parameter variable">-it</span> centos:7

<span class="token function">docker</span> container <span class="token function">ls</span> 

<span class="token function">docker</span> <span class="token builtin class-name">exec</span> <span class="token parameter variable">-i</span> 容器ID <span class="token function">bash</span>

<span class="token function">docker</span> <span class="token builtin class-name">exec</span> <span class="token parameter variable">-it</span> 容器ID  <span class="token function">bash</span>

<span class="token comment"># 说明：从这个stdin中exit，不会导致容器的停止。</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="导出和导入容器" tabindex="-1"><a class="header-anchor" href="#导出和导入容器" aria-hidden="true">#</a> 导出和导入容器</h2><h4 id="导出容器-docker-export" tabindex="-1"><a class="header-anchor" href="#导出容器-docker-export" aria-hidden="true">#</a> 导出容器 docker export</h4><p>如果要导出本地某个容器，可以使用<code>docker export</code>命令</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> container <span class="token function">ls</span> <span class="token parameter variable">-a</span> 

<span class="token function">docker</span> <span class="token builtin class-name">export</span> 容器ID <span class="token operator">&gt;</span> filename.tar  
<span class="token comment">## 这样将导出容器快照到本地文件</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="导入容器快照-docker-inport" tabindex="-1"><a class="header-anchor" href="#导入容器快照-docker-inport" aria-hidden="true">#</a> 导入容器快照 docker inport</h4><p>可以使用<code>docker import</code>从容器快照文件中再导入为镜像</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> filename.tar <span class="token operator">|</span> <span class="token function">docker</span> <span class="token function">import</span> - test/centos:v2.0
<span class="token function">docker</span> image <span class="token function">ls</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>此外，也可以通过制定URL或者某个目录来导入</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> <span class="token function">import</span> http://example.com/exampleimage.tgz example/imagerepo
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>说明：</strong><br> 用户既可以使用<code>docker load</code>来导入镜像存储文件到本地镜像库，也可以使用<code>docker import</code>来导入一个容器快照到本地镜像库。两者的区别在于容器快照文件将丢弃所有的历史记录和元数据信息(即仅保存容器当时的快照状态)，而镜像存储文件将保存完整记录，体积也要大。从容器快照文件导入时可以重新制定标签等元数据信息。</p><h2 id="删除容器" tabindex="-1"><a class="header-anchor" href="#删除容器" aria-hidden="true">#</a> 删除容器</h2><p>可以使用<code>docker container rm</code>来删除一个处于中止状态的容器。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> container <span class="token function">rm</span> 容器ID或容器名      <span class="token comment">#删除容器</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>如果要删除一个运行中的容器，可以添加<code>-f</code>参数，Docker会发送SIGKILL信号给容器</p><h3 id="清理所有处于终止状态的容器" tabindex="-1"><a class="header-anchor" href="#清理所有处于终止状态的容器" aria-hidden="true">#</a> 清理所有处于终止状态的容器</h3><p>用<code>docker container ls -a</code>命令可以查看所有已经创建的包括终止状态的容器，当数量过多，可以用下面的命令清理掉所有处于终止状态的容器</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> container prune      <span class="token comment">#删除所有处于终止状态的容器</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,54);function v(m,h){const e=o("router-link");return d(),l("div",null,[p,n("nav",u,[n("ul",null,[n("li",null,[s(e,{to:"#启动容器"},{default:c(()=>[a("启动容器")]),_:1}),n("ul",null,[n("li",null,[s(e,{to:"#启动容器-1"},{default:c(()=>[a("启动容器")]),_:1})]),n("li",null,[s(e,{to:"#新建并启动"},{default:c(()=>[a("新建并启动")]),_:1})]),n("li",null,[s(e,{to:"#启动已终止的容器"},{default:c(()=>[a("启动已终止的容器")]),_:1})])])]),n("li",null,[s(e,{to:"#后台运行"},{default:c(()=>[a("后台运行")]),_:1})]),n("li",null,[s(e,{to:"#终止容器"},{default:c(()=>[a("终止容器")]),_:1})]),n("li",null,[s(e,{to:"#进入容器"},{default:c(()=>[a("进入容器")]),_:1}),n("ul",null,[n("li",null,[s(e,{to:"#attach命令"},{default:c(()=>[a("attach命令")]),_:1})]),n("li",null,[s(e,{to:"#使用exec命令"},{default:c(()=>[a("使用exec命令")]),_:1})])])]),n("li",null,[s(e,{to:"#导出和导入容器"},{default:c(()=>[a("导出和导入容器")]),_:1})]),n("li",null,[s(e,{to:"#删除容器"},{default:c(()=>[a("删除容器")]),_:1}),n("ul",null,[n("li",null,[s(e,{to:"#清理所有处于终止状态的容器"},{default:c(()=>[a("清理所有处于终止状态的容器")]),_:1})])])])])]),b])}const f=i(r,[["render",v],["__file","Docker系列学习-05.操作Docker容器.html.vue"]]);export{f as default};
